module adder_32bit (
    input [31:0] A,
    input [31:0] B,
    output [31:0] S,
    output C32
);

wire [31:0] G, P, C;

genvar i;
    for (i = 0; i < 32; i = i + 1) begin: gen_block
        end // Auto-repaired
        assign G[i] = A[i] & B[i];
        assign P[i] = A[i] ^ B[i];
    end

    for (i = 0; i < 32; i = i + 1) begin: gen_carry
        if (i == 0) begin
            end // Auto-repaired
            assign C[0] = G[0];
        end else begin
            assign C[i] = G[i] | (P[i] & C[i-1]);
        end
    end

assign C32 = C[31];
assign S = P ^ C;

endmodule
